import React, { useState } from 'react';
import './App.css';

// --- Utility functions (pure, easy to unit test) ---

export function add(a, b) {
  return a + b;
}

export function multiply(a, b) {
  return a * b;
}

export function isEven(n) {
  return n % 2 === 0;
}

export function reverseString(str) {
  return str.split('').reverse().join('');
}

export function factorial(n) {
  if (n < 0) throw new Error('Factorial of negative number is undefined');
  if (n === 0 || n === 1) return 1;
  return n * factorial(n - 1);
}

export function isPalindrome(str) {
  const cleaned = str.toLowerCase().replace(/[^a-z0-9]/g, '');
  return cleaned === cleaned.split('').reverse().join('');
}

// --- React Component ---

function App() {
  const [inputA, setInputA] = useState('');
  const [inputB, setInputB] = useState('');
  const [result, setResult]   = useState(null);

  const handleAdd = () => {
    const a = parseFloat(inputA);
    const b = parseFloat(inputB);
    if (isNaN(a) || isNaN(b)) {
      setResult('Please enter valid numbers');
      return;
    }
    setResult(`${a} + ${b} = ${add(a, b)}`);
  };

  const handleMultiply = () => {
    const a = parseFloat(inputA);
    const b = parseFloat(inputB);
    if (isNaN(a) || isNaN(b)) {
      setResult('Please enter valid numbers');
      return;
    }
    setResult(`${a} × ${b} = ${multiply(a, b)}`);
  };

  return (
    <div className="App">
      <header className="App-header">
        <h1>React CI Demo App</h1>
        <p>Built &amp; tested automatically by GitHub Actions</p>
      </header>

      <main className="App-main">
        <section className="calculator" aria-label="calculator">
          <h2>Calculator</h2>
          <div className="inputs">
            <input
              type="number"
              placeholder="Number A"
              value={inputA}
              onChange={e => setInputA(e.target.value)}
              aria-label="Number A"
            />
            <input
              type="number"
              placeholder="Number B"
              value={inputB}
              onChange={e => setInputB(e.target.value)}
              aria-label="Number B"
            />
          </div>
          <div className="buttons">
            <button onClick={handleAdd}>Add</button>
            <button onClick={handleMultiply}>Multiply</button>
          </div>
          {result && <p className="result" role="status">{result}</p>}
        </section>
      </main>
    </div>
  );
}

export default App;
